import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { defaultEmailPreferences } from '../../src/models/user-preferences.js';
import type { UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let eventBus: EventBus;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository, eventBus);
    resetPreferencesIdCounter();
  });

  describe('createDefaultPreferences', () => {
    it('should create default preferences for a user', async () => {
      const prefs = await service.createDefaultPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(
        defaultEmailPreferences.subscribedCategories,
      );
    });

    it('should return existing preferences without creating duplicates', async () => {
      const first = await service.createDefaultPreferences('user-1');
      const second = await service.createDefaultPreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(repository.count()).toBe(1);
    });

    it('should auto-create preferences on user:created event', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
      expect(prefs!.email.enabled).toBe(true);
    });
  });

  describe('getPreferences', () => {
    it('should return undefined for unknown user', () => {
      expect(service.getPreferences('nonexistent')).toBeUndefined();
    });

    it('should return preferences for a known user', async () => {
      await service.createDefaultPreferences('user-1');
      const prefs = service.getPreferences('user-1');

      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.email.enabled).toBe(false);
      // Other fields unchanged
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.subscribedCategories).toEqual(
        defaultEmailPreferences.subscribedCategories,
      );
    });

    it('should change frequency', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { frequency: 'daily' });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update subscribed categories', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(updated.email.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should update multiple fields at once', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        enabled: true,
        frequency: 'weekly',
        subscribedCategories: ['order_confirmation', 'order_status_update'],
      });

      expect(updated.email.enabled).toBe(true);
      expect(updated.email.frequency).toBe('weekly');
      expect(updated.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
      ]);
    });

    it('should throw for unknown user', () => {
      expect(() =>
        service.updateEmailPreferences('nonexistent', { enabled: false }),
      ).toThrow('Preferences not found for user: nonexistent');
    });

    it('should update the updatedAt timestamp', async () => {
      const prefs = await service.createDefaultPreferences('user-1');
      const originalUpdatedAt = prefs.updatedAt;

      // Small delay to ensure different timestamp
      await new Promise((r) => setTimeout(r, 5));

      const updated = service.updateEmailPreferences('user-1', { frequency: 'daily' });
      expect(updated.updatedAt.getTime()).toBeGreaterThan(originalUpdatedAt.getTime());
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendEmail('unknown-user', 'order_confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', async () => {
      await service.createDefaultPreferences('user-1');
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false for unsubscribed category even when email is enabled', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateEmailPreferences('user-1', {
        subscribedCategories: [],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'user_welcome')).toBe(false);
    });
  });
});
